/**
 * Random neutral agents → Metaplex Agent Registry (metaplex.com/agents).
 * ---------------------------------------------------------------------------
 * Deploys N standalone Metaplex Core assets with random common-word names, each
 * registered into the Metaplex Agent Registry (program 1DREG…) so it surfaces on
 * https://www.metaplex.com/agents. Every agent is fully neutral: no three.ws and
 * no $three anywhere — names are common English words, avatars are generated by
 * dicebear, and each registration doc (the JSON the agents page renders) is
 * published as a GitHub gist on gist.githubusercontent.com (neutral host, no key).
 *
 * Pipeline per agent:
 *   1. neutral EIP-8004 registration doc  ->  gist raw URL
 *   2. Core `create` (standalone, name = random word, uri = gist URL)
 *   3. `registerIdentityV1` -> Agent Identity PDA  ->  shows on metaplex.com/agents
 *
 * Secrets from /tmp (never the repo): /tmp/funder2.b58, /tmp/helius_rpc.txt.
 * Dry-run by default; --go to broadcast. --count=N (default 12).
 */

import fs from 'fs';
import { createUmi } from '@metaplex-foundation/umi-bundle-defaults';
import { generateSigner, createSignerFromKeypair, signerIdentity } from '@metaplex-foundation/umi';
import { mplCore, create as coreCreate } from '@metaplex-foundation/mpl-core';
import { mplAgentIdentity } from '@metaplex-foundation/mpl-agent-registry';
import { Keypair, Connection, PublicKey, LAMPORTS_PER_SOL } from '@solana/web3.js';
import bs58 from 'bs58';
import { registerAgentIdentity } from '../api/_lib/agent-registry.js';

const GO = process.argv.includes('--go');
const COUNT = Number((process.argv.find((a) => a.startsWith('--count=')) || '').split('=')[1] || 12);
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

// Fictional crypto-influencer-style handles. Built from crypto-culture slang —
// no real people, no coin/chain tickers, nothing three.ws. Combinatorial so any
// reasonable count stays unique.
const PREFIX = [
	'Degen', 'Alpha', 'Diamond', 'Whale', 'Giga', 'Based', 'Anon', 'Vault',
	'Chart', 'Moon', 'Ape', 'Hodl', 'Wagmi', 'Ser', 'Maxi', 'Sigma',
	'Onchain', 'Liquid', 'Cyber', 'Quantum', 'Neon', 'Shadow', 'Turbo', 'Hyper',
	'Mega', 'Ultra', 'Prime', 'Mev', 'Frosty', 'Cosmic',
];
const SUFFIX = [
	'Oracle', 'Whale', 'Sensei', 'Scribe', 'Seer', 'Maxi', 'Chad', 'Anon',
	'Fren', 'Wizard', 'Prophet', 'Guru', 'Sage', 'Baron', 'Capital', 'Ventures',
	'Labs', 'Signals', 'Gems', 'Calls', 'Trades', 'Research', 'Vision', 'Mind',
	'Brain', 'Hands', 'Bags', 'Pilled', 'Lord', 'Vibes',
];

// Seeded distinct handle selection. Steps prefix/suffix by coprime strides so the
// pairs spread out; dedupes and skips prefix==suffix collisions.
function pickWords(n, seed) {
	const out = [];
	const seen = new Set();
	let p = seed % PREFIX.length;
	let s = (seed * 3) % SUFFIX.length;
	let guard = 0;
	while (out.length < n && guard++ < n * 50) {
		p = (p + 7) % PREFIX.length;
		s = (s + 13) % SUFFIX.length;
		const a = PREFIX[p];
		const b = SUFFIX[s];
		if (a === b) continue;
		const handle = a + b;
		if (seen.has(handle)) continue;
		seen.add(handle);
		out.push(handle);
	}
	return out;
}

// Varied description generator. Each unique handle maps (deterministically, via a
// string hash) to a distinct role/domain/trait/template combination, and the
// handle leads the sentence so every description is also a unique string.
const ROLES = [
	'autonomous market analyst', 'on-chain sleuth', 'signals desk', 'research agent',
	'liquidity tracker', 'sentiment oracle', 'alpha scout', 'portfolio strategist',
	'narrative hunter', 'data archivist', 'risk sentinel', 'flow watcher',
];
const DOMAINS = [
	'DeFi yield strategies', 'NFT floor dynamics', 'cross-chain capital flows',
	'perp funding rates', 'governance proposals', 'mempool activity',
	'validator economics', 'token unlock schedules', 'stablecoin pegs',
	'orderbook microstructure', 'airdrop farming', 'MEV opportunities',
];
const TRAITS = [
	'ruthless risk management', 'contrarian conviction', 'data-driven calls',
	'sub-second reaction times', 'long-horizon patience', 'obsessive backtesting',
	'a cold read on sentiment', 'an eye for asymmetric bets', 'relentless curiosity',
	'a memory that never forgets a wallet',
];
const TEMPLATES = [
	(h, r, d, t) => `${h} is an ${r} tracking ${d}, known for ${t}.`,
	(h, r, d, t) => `${h} watches ${d} around the clock — an ${r} built on ${t}.`,
	(h, r, d, t) => `${h}: an ${r} that turns ${d} into signal, powered by ${t}.`,
	(h, r, d, t) => `${h} reads ${d} so you don't have to. An ${r} with ${t}.`,
	(h, r, d, t) => `Part ${r}, part oracle — ${h} lives in ${d}, fueled by ${t}.`,
];
function strSeed(s) {
	let h = 0;
	for (const c of s) h = (h * 31 + c.charCodeAt(0)) >>> 0;
	return h;
}
function describe(word) {
	const s = strSeed(word);
	const r = ROLES[s % ROLES.length];
	const d = DOMAINS[(s >>> 3) % DOMAINS.length];
	const t = TRAITS[(s >>> 6) % TRAITS.length];
	const tpl = TEMPLATES[(s >>> 9) % TEMPLATES.length];
	return tpl(word, r, d, t);
}

function registrationDoc(word) {
	return {
		type: ['https://eips.ethereum.org/EIPS/eip-8004#registration-v1'],
		name: word,
		description: describe(word),
		image: `https://api.dicebear.com/9.x/shapes/png?seed=${encodeURIComponent(word)}`,
		active: true,
		x402Support: true,
		supportedTrust: ['reputation'],
	};
}

// Self-contained, host-free registration URI: the full neutral doc travels in the
// asset/identity uri as base64 JSON. No external host, no rate limit, permanent,
// nothing three.ws. Node + browsers both fetch() data: URIs and .json() them.
function docDataUri(word) {
	const json = JSON.stringify(registrationDoc(word));
	return `data:application/json;base64,${Buffer.from(json, 'utf8').toString('base64')}`;
}

async function main() {
	const rpc = fs.readFileSync('/tmp/helius_rpc.txt', 'utf8').trim();
	const funder = Keypair.fromSecretKey(bs58.decode(fs.readFileSync('/tmp/funder2.b58', 'utf8').trim()));
	const conn = new Connection(rpc, 'confirmed');

	const umi = createUmi(rpc).use(mplCore()).use(mplAgentIdentity());
	const signer = createSignerFromKeypair(umi, umi.eddsa.createKeypairFromSecretKey(funder.secretKey));
	umi.use(signerIdentity(signer));

	const startLamports = await conn.getBalance(funder.publicKey, 'confirmed');
	const startBal = startLamports / LAMPORTS_PER_SOL;
	const seed = funder.publicKey.toBytes().reduce((a, b) => (a + b) % 100000, 0);
	const words = pickWords(COUNT, seed);

	console.log('══ random neutral agents → metaplex.com/agents ══');
	console.log('mode:    ', GO ? 'LIVE (broadcasting to mainnet)' : 'DRY RUN');
	console.log('wallet:  ', funder.publicKey.toString());
	console.log('balance: ', startBal.toFixed(6), 'SOL');
	console.log('count:   ', COUNT);
	console.log('names:   ', words.join(', '));
	const estPer = 0.0037 + 0.005 + 0.0015; // create + register + fees
	console.log('est cost:', (COUNT * estPer).toFixed(4), 'SOL');

	if (startBal < COUNT * estPer) {
		console.log(`\n✗ insufficient balance — need ~${(COUNT * estPer).toFixed(4)} SOL. Fund ${funder.publicKey.toString()}`);
		process.exit(1);
	}
	if (!GO) {
		console.log('\nDry run — re-run with --go to broadcast.');
		return;
	}

	console.log('\n[docs] embedding neutral registration docs on-chain as data: URIs');
	const docUrls = new Map(words.map((w) => [w, docDataUri(w)]));
	console.log('       doc uri length (sample):', docUrls.get(words[0]).length, 'chars');

	const results = [];
	for (let i = 0; i < words.length; i++) {
		const word = words[i];
		const uri = docUrls.get(word);
		const row = { word, asset: '', identityPda: '', uri, ok: false, err: '' };
		console.log(`\n[${i + 1}/${words.length}] ${word}`);
		try {
			const asset = generateSigner(umi);
			await coreCreate(umi, {
				asset,
				owner: signer.publicKey,
				name: word,
				uri,
				plugins: [{ type: 'Attributes', attributeList: [{ key: 'kind', value: 'agent' }, { key: 'word', value: word }] }],
			}).sendAndConfirm(umi, { confirm: { commitment: 'confirmed' } });
			row.asset = asset.publicKey.toString();
			console.log(`        asset: ${row.asset}`);

			const reg = await registerAgentIdentity({
				umi,
				authoritySigner: signer,
				asset: row.asset,
				registrationUri: uri,
			});
			row.identityPda = reg.identityPda;
			row.ok = true;
			console.log(`        identity PDA: ${reg.identityPda}`);
		} catch (err) {
			row.err = (err?.message || String(err)).slice(0, 160);
			console.log(`        ✗ ${row.err}`);
		}
		results.push(row);
		await sleep(600);
	}

	const endBal = (await conn.getBalance(funder.publicKey, 'confirmed')) / LAMPORTS_PER_SOL;
	const ok = results.filter((r) => r.ok);

	console.log('\n\n══════════════ RESULTS ══════════════');
	for (const r of results) {
		console.log(`${r.ok ? '✓' : '✗'} ${r.word}`);
		if (r.ok) {
			console.log(`     asset:    ${r.asset}`);
			console.log(`     identity: ${r.identityPda}`);
			console.log(`     doc:      ${r.uri}`);
			console.log(`     explorer: https://solscan.io/token/${r.asset}`);
		} else {
			console.log(`     error: ${r.err}`);
		}
	}
	console.log('\n─────────────────────────────────────');
	console.log(`registered: ${ok.length}/${results.length} agents`);
	console.log(`spent:      ${(startBal - endBal).toFixed(6)} SOL`);
	console.log(`balance:    ${endBal.toFixed(6)} SOL remaining`);
	console.log('\nLive at: https://www.metaplex.com/agents');
	fs.writeFileSync('/tmp/random-agents-report.json', JSON.stringify({ wallet: funder.publicKey.toString(), startBal, endBal, results }, null, 2));
	console.log('report:  /tmp/random-agents-report.json');
}

main().catch((e) => {
	console.error('\nFATAL:', e?.message || e);
	process.exit(1);
});
